// Resolve slugs from sidebar references
function getSlug(link) { if (!link) return ''; return link.split('/').pop(); }

// Fixup: items that don't have separate sidebar slugs get their parent slug
var fixupMap = {};
// All sub-items of لائحة عمل (section[39]) - الأمير, اللجنة المالية, etc. don't have separate slugs
// They inherit from the parent section (si:39 = 1006)
// المحور الأول/الثاني/الثالث are parts of رسالة بخصوص التعامل (si:1 = 968)

var result = sections.map(function(section) {
  var resolvedItems = section.items.map(function(item) {
    var slug = '';
    var hasCo = typeof item.co !== 'undefined' && item.co !== null;
    var hasSi = typeof item.si !== 'undefined' && item.si !== null;
    var hasCi = typeof item.ci !== 'undefined' && item.ci !== null;
    
    try {
      if (hasCo && hasCi) {
        var parent = sidebar[item.co];
        if (hasSi) {
          // Check if section exists
          if (parent.chapters[item.ci] && parent.chapters[item.ci].sections && parent.chapters[item.ci].sections[item.si]) {
            slug = getSlug(parent.chapters[item.ci].sections[item.si].link);
          } else {
            // No separate section slug; use chapter slug
            slug = getSlug(parent.chapters[item.ci].link);
            console.log('  [warn] no section ' + item.si + ' for chapter ' + item.ci + ', using chapter slug');
          }
        } else {
          slug = getSlug(parent.chapters[item.ci].link);
        }
      } else if (hasSi) {
        slug = getSlug(sidebar[item.si].link);
      }
    } catch(e) {
      console.log('  [error] item: ' + (item.t || '').substring(0, 30) + ' error: ' + e.message);
    }
    // Items with ns:true have no separate slug; leave slug empty
    if (item.ns) slug = '';
    // Extract page number from slug prefix; fall back to item.p
    var pageNum = item.p;
    if (slug) {
      var n = parseInt(slug.split('-')[0]);
      if (!isNaN(n)) pageNum = n;
    }
    return { title: item.t, slug: slug, page: pageNum };
  });
  return { divider: section.divider, items: resolvedItems };
});

// Write atiyatullah-index.json
var outputPath = path.join(__dirname, '..', 'src', 'data', 'atiyatullah-index.json');
fs.writeFileSync(outputPath, JSON.stringify(result, null, 2), 'utf-8');
console.log('Written: ' + outputPath);
var total = result.reduce(function(a,s){return a+s.items.length;},0);
console.log('Sections: ' + result.length + ', total items: ' + total);
result.forEach(function(s,i){console.log('  ['+i+'] ' + s.divider.substring(0,40) + ' items=' + s.items.length);});

// Update print-mappings.json with slug→page entries for atiyatullah
var printMappingsPath = path.join(__dirname, '..', 'src', 'data', 'print-mappings.json');
var printMappings = JSON.parse(fs.readFileSync(printMappingsPath, 'utf-8'));
var atiyatullahMappings = printMappings['atiyatullah'] || {};
var added = 0;
result.forEach(function(section) {
  section.items.forEach(function(item) {
    if (!item.slug || !item.page) return;
    var pageStr = String(item.page);
    // Skip if already in original print-mappings (avoid overwriting good entries)
    if (atiyatullahMappings[pageStr]) return;
    if (!atiyatullahMappings[pageStr]) {
      atiyatullahMappings[pageStr] = [];
    }
    if (atiyatullahMappings[pageStr].indexOf(item.slug) === -1) {
      atiyatullahMappings[pageStr].push(item.slug);
      added++;
    }
  });
});
printMappings['atiyatullah'] = atiyatullahMappings;
fs.writeFileSync(printMappingsPath, JSON.stringify(printMappings, null, 2), 'utf-8');
console.log('Added ' + added + ' slug→page mappings to print-mappings.json');
